function calculate({ initialImplementationCost, annualSubscriptionCost, trainingHoursPerEmployee, avgEmployeeHourlyWage, numEmployeesAffected, currentAnnualRevenue, estimatedRevenueGrowth, currentAnnualOperatingCosts, estimatedCostSavings, estimatedProductivityGain }) {

  // Input validation and clamping to ensure non-negative values and sensible percentages
  initialImplementationCost = Math.max(0, initialImplementationCost || 0);
  annualSubscriptionCost = Math.max(0, annualSubscriptionCost || 0);
  trainingHoursPerEmployee = Math.max(0, trainingHoursPerEmployee || 0);
  avgEmployeeHourlyWage = Math.max(0, avgEmployeeHourlyWage || 0);
  numEmployeesAffected = Math.max(0, numEmployeesAffected || 0);
  currentAnnualRevenue = Math.max(0, currentAnnualRevenue || 0);
  estimatedRevenueGrowth = Math.max(0, Math.min(100, estimatedRevenueGrowth || 0)); // Cap at 100%
  currentAnnualOperatingCosts = Math.max(0, currentAnnualOperatingCosts || 0);
  estimatedCostSavings = Math.max(0, Math.min(100, estimatedCostSavings || 0)); // Cap at 100%
  estimatedProductivityGain = Math.max(0, Math.min(100, estimatedProductivityGain || 0)); // Cap at 100%

  // Convert percentages to decimals
  const revenueGrowthFactor = estimatedRevenueGrowth / 100;
  const costSavingsFactor = estimatedCostSavings / 100;
  const productivityGainFactor = estimatedProductivityGain / 100;

  // Step 1: Calculate Total Initial Investment (One-time Costs)
  const totalTrainingCost = trainingHoursPerEmployee * avgEmployeeHourlyWage * numEmployeesAffected;
  const totalInitialInvestment = initialImplementationCost + totalTrainingCost;

  // Step 2: Calculate First-Year Total Investment
  const totalFirstYearInvestment = totalInitialInvestment + annualSubscriptionCost;

  // Step 3: Calculate Annual Monetary Benefits
  const revenueGrowthBenefit = currentAnnualRevenue * revenueGrowthFactor;
  const operationalCostSavings = currentAnnualOperatingCosts * costSavingsFactor;

  // Productivity gain is monetized as the value of freed-up employee time or increased output capacity.
  // Using 2080 hours per year (40 hours/week * 52 weeks) as standard annual working hours.
  const totalAnnualEmployeeCostAffected = avgEmployeeHourlyWage * 2080 * numEmployeesAffected;
  const productivityGainMonetary = totalAnnualEmployeeCostAffected * productivityGainFactor;

  const annualRecurringBenefit = operationalCostSavings + revenueGrowthBenefit + productivityGainMonetary;

  // Step 4: Calculate Net First-Year Monetary Benefit
  // This is the recurring benefit minus the annual subscription cost (ongoing cost)
  const netFirstYearBenefit = annualRecurringBenefit - annualSubscriptionCost;

  // Step 5: Calculate First-Year ROI
  let firstYearROI = 0;
  if (totalFirstYearInvestment > 0) {
    // ROI = (Total Benefits Year 1 - Total Costs Year 1) / Total Costs Year 1 * 100
    // Total Benefits Year 1 = annualRecurringBenefit
    // Total Costs Year 1 = totalFirstYearInvestment
    firstYearROI = ((annualRecurringBenefit - totalFirstYearInvestment) / totalFirstYearInvestment) * 100;
  } else if (annualRecurringBenefit > 0) {
    firstYearROI = Infinity; // Infinite ROI if investment is zero but benefit is positive
  } else {
    firstYearROI = 0; // No investment, no benefit
  }

  // Step 6: Calculate Payback Period
  let paybackPeriod = Infinity;
  if (netFirstYearBenefit > 0) { // Only calculate if there's a positive net recurring benefit
    paybackPeriod = totalInitialInvestment / netFirstYearBenefit;
  } else if (totalInitialInvestment === 0) {
    paybackPeriod = 0; // No initial investment, instantly paid back
  }

  // Cap payback period for very long periods to avoid misleadingly large numbers, indicating it's not a short-term payback.
  if (paybackPeriod > 50) { 
    paybackPeriod = Infinity; 
  }

  return {
    totalInitialInvestment: totalInitialInvestment,
    totalFirstYearInvestment: totalFirstYearInvestment,
    annualRecurringBenefit: annualRecurringBenefit,
    netFirstYearBenefit: netFirstYearBenefit,
    firstYearROI: firstYearROI,
    paybackPeriod: paybackPeriod
  };
}
